#include<bits/stdc++.h>
using namespace std;
#define int long long
#define endl '\n'
const int mod=1e9+7;
const int inf=1e13;
int max(int A,int B){return (A>B)?A:B;}
int min(int A,int B){return (A<B)?A:B;}
int gcd(int a,int b){return b?gcd(b,a%b):a;}
int lcm(int a,int b){return a*b/gcd(a,b);}
int n,a,b;
bool check(int w[],int k){
	for(int i=0;i<n;i++) w[i]-=a*k;
	int i=0;
	while(k!=0){
		if(w[i]!=0) k-=w[i]/(a+b);
		if(w[i]%(a+b)!=0) k--;
		w[i]=0;i++;
	}bool b=0;
	for(int j=0;j<n;j++)
		if(w[j]!=0){b^=1;break;}
	if(b) return 0;
	return 1;
}signed main(){
	ios::sync_with_stdio(0),
	cin.tie(0),cout.tie(0);
	cin>>n>>a>>b;
	int w[n];
	for(int i=0;i<n;i++) cin>>w[i];
	int l=n,r=0,mid;
	while(l+1<r){ 
		mid=(l+r)>>1;
		if(check(w,mid)) r=mid; 
		else l=mid; 
	}cout<<r+1;return 0;
}
